def _extract_identity_markers(text: str) -> dict:
    """Extract potential identity signals from text."""
    markers = {
        'pronouns': re.findall(r'\b(i|me|my|mine|we|us|our|ours)\b', text),
        'self_references': re.findall(r'\b(myself|ourselves)\b', text),
        'role_indicators': re.findall(r'\b(as a|being|identifying as)\s+(\w+)', text)
    }
    return {k: v for k, v in markers.items() if v}

